// Reset all child pointers when function_page is deleted
static void reset_function_page_children(void) {
    scan_status_label = NULL;
    scan_list = NULL;
    wifi_sas_page = 0;
    wifi_sas_nav_bar = NULL; wifi_sas_nav_prev = NULL;
    wifi_sas_nav_lbl = NULL; wifi_sas_nav_next = NULL;
    deauth_list = NULL;
    deauth_prompt_label = NULL;
    deauth_fps_label = NULL;
    deauth_pause_btn = NULL;
    deauth_quit_btn = NULL;
    evil_twin_network_dd = NULL;
    evil_twin_html_dd = NULL;
    evil_twin_start_btn = NULL;
    evil_twin_status_label = NULL;
    evil_twin_log_ta = NULL;
    evil_twin_content = NULL;
    evil_twin_ssid_label = NULL;
    evil_twin_deauth_list_label = NULL;
    evil_twin_status_list = NULL;
    blackout_networks_label = NULL;
    blackout_status_label = NULL;
    blackout_stop_btn = NULL;
    snifferdog_kick_label = NULL;
    snifferdog_recent_label = NULL;
    snifferdog_stop_btn = NULL;
    sniffer_log_ta = NULL;
    sniffer_stop_btn = NULL;
    sniffer_start_btn = NULL;
    sniffer_packets_label = NULL;
    sniffer_aps_label = NULL;
    sniffer_probes_label = NULL;
    sniffer_channel_label = NULL;
    sniffer_ap_list = NULL;
    sniffer_observe_mode = false;
    sniffer_observe_ap_index = -1;
    sae_overflow_log_ta = NULL;
    sae_overflow_stop_btn = NULL;
    handshake_log_ta = NULL;
    handshake_stop_btn = NULL;
    handshake_status_list = NULL;
    wardrive_log_ta = NULL;
    wardrive_stop_btn = NULL;
    wardrive_ui_active = false;
    if (wd_ui_timer) { lv_timer_del(wd_ui_timer); wd_ui_timer = NULL; }
    if (wd_ui_gps_label && lv_obj_is_valid(wd_ui_gps_label)) lv_obj_del(wd_ui_gps_label);
    wd_ui_gps_label = NULL;
    wd_ui_counter_label = NULL;
    wd_ui_ble_label = NULL;
    wd_ui_channel_label = NULL;
    wd_ui_header = NULL;
    wd_ui_table = NULL;
    karma_log_ta = NULL;
    karma_stop_btn = NULL;
    karma_content = NULL;
    karma_probe_dd = NULL;
    karma_html_dd = NULL;
    karma_start_btn = NULL;
    karma_info_ssid_label = NULL;
    karma_info_filename_label = NULL;
    portal_content = NULL;
    portal_ssid_ta = NULL;
    portal_html_dd = NULL;
    portal_start_btn = NULL;
    portal_keyboard = NULL;
    ble_scan_content = NULL;
    ble_scan_list = NULL;
    ble_scan_status_label = NULL;
    screenshot_btn = NULL;
    deauth_monitor_list = NULL;
    deauth_monitor_status_label = NULL;
    deauth_monitor_known_label = NULL;
    bt_sas_list = NULL;
    bt_sas_status_label = NULL;
    bt_sas_next_btn = NULL;
    bt_sas_save_overlay = NULL;
    bt_sas_save_ta = NULL;
    bt_sas_ui_active = false;
    bt_sas_selected_idx = -1;
    airtag_scan_status_label = NULL;
    airtag_scan_stats_label1 = NULL;
    airtag_scan_stats_label2 = NULL;
    airtag_scan_stats_label3 = NULL;
    airtag_view_tags_btn = NULL;
    drone_list        = NULL;
    drone_status_lbl  = NULL;
    drone_count_lbl   = NULL;
    drone_rec_lbl     = NULL;
    drone_ui_active   = false;
    // WiFi Analyzer cleanup
    wana_chart_obj = NULL;
    wana_status_lbl = NULL; wana_panel = NULL;
    wana_lbl_count = 0; wana_ssid_count = 0; wana_scroll_x = 0;
    wana_active = false; wana_scanning = false; wana_scroll_paused = false;
    if (wana_scroll_timer) { lv_timer_del(wana_scroll_timer); wana_scroll_timer = NULL; }
    if (wana_ui_timer)     { lv_timer_del(wana_ui_timer);     wana_ui_timer     = NULL; }
    if (wana_buf)          { heap_caps_free(wana_buf);         wana_buf          = NULL; }
    // WiFi Band Scope cleanup
    wscope_canvas = NULL; wscope_status_lbl = NULL; wscope_active = false;
    if (wscope_ui_timer) { lv_timer_del(wscope_ui_timer); wscope_ui_timer = NULL; }
    if (wscope_buf)      { heap_caps_free(wscope_buf);     wscope_buf = NULL; }
    // CC1101 Band Scope cleanup (safe to call from any screen transition)
    if (s_bs) {
        s_bs->active = false; s_bs->cancel = true;
        s_bs->canvas = NULL; s_bs->status_lbl = NULL; s_bs->start_btn = NULL;
        if (s_bs->tmr) { lv_timer_del(s_bs->tmr); s_bs->tmr = NULL; }
        if (!s_bs->task) { if (s_bs->canv_buf) heap_caps_free(s_bs->canv_buf); heap_caps_free(s_bs); s_bs = NULL; }
    }
    // nRF24 channel-scan cleanup
    if (s_ncs) {
        s_ncs->active = false; s_ncs->cancel = true;
        s_ncs->canvas = NULL; s_ncs->status_lbl = NULL; s_ncs->start_btn = NULL;
        if (s_ncs->tmr) { lv_timer_del(s_ncs->tmr); s_ncs->tmr = NULL; }
        if (!s_ncs->task) { if (s_ncs->canv_buf) heap_caps_free(s_ncs->canv_buf); heap_caps_free(s_ncs); s_ncs = NULL; }
    }
    // nRF24 sniffer cleanup
    if (s_nsniff) {
        s_nsniff->active = false; s_nsniff->cancel = true;
        s_nsniff->status_lbl = NULL; s_nsniff->hex_lbl = NULL;
        s_nsniff->count_lbl = NULL; s_nsniff->start_btn = NULL;
        if (s_nsniff->tmr) { lv_timer_del(s_nsniff->tmr); s_nsniff->tmr = NULL; }
        if (!s_nsniff->task) { heap_caps_free(s_nsniff); s_nsniff = NULL; }
    }
    // CC1101 TPMS cleanup
    if (s_tpms) {
        s_tpms->active = false; s_tpms->cancel = true;
        s_tpms->status_lbl = NULL; s_tpms->count_lbl = NULL;
        s_tpms->start_btn = NULL;
        s_tpms->freq_315_btn = NULL; s_tpms->freq_433_btn = NULL;
        s_tpms->scroll_cont = NULL;
        for (int _i = 0; _i < TPMS_MAX_SENSORS; _i++) s_tpms->sensor_lbl[_i] = NULL;
        if (s_tpms->tmr) { lv_timer_del(s_tpms->tmr); s_tpms->tmr = NULL; }
        /* log_fp is owned exclusively by the task; it closes it on exit.
         * Closing here while the task may be mid-fprintf causes a crash. */
        if (!s_tpms->task) { heap_caps_free(s_tpms); s_tpms = NULL; }
    }
    // nRF24 Futaba cleanup
    if (s_nfut) {
        s_nfut->active = false; s_nfut->cancel = true;
        s_nfut->status_lbl = NULL; s_nfut->result_lbl = NULL; s_nfut->start_btn = NULL;
        if (s_nfut->tmr) { lv_timer_del(s_nfut->tmr); s_nfut->tmr = NULL; }
        if (!s_nfut->task) { heap_caps_free(s_nfut); s_nfut = NULL; }
    }
    // nRF24 jammer cleanup
    s_n24_jam_active = false;
    s_n24_jam_status = NULL;
    if (s_n24_jam_tmr) { lv_timer_del(s_n24_jam_tmr); s_n24_jam_tmr = NULL; }
    // Zigbee Scout cleanup — main thread owns the free (task only sets task=NULL)
    if (s_zgwd) {
        s_zgwd->cancel = true; s_zgwd->scanning = false;
        s_zgwd->status_lbl = NULL; s_zgwd->pan_list = NULL;
        s_zgwd->passive_btn = NULL; s_zgwd->active_btn = NULL;
        if (s_zgwd->tmr) { lv_timer_del(s_zgwd->tmr); s_zgwd->tmr = NULL; }
        if (!s_zgwd->task) { heap_caps_free(s_zgwd); s_zgwd = NULL; }
    }
    if (s_zgwd_loc) {
        s_zgwd_loc->running = false;
        if (s_zgwd_loc->tmr) { lv_timer_del(s_zgwd_loc->tmr); s_zgwd_loc->tmr = NULL; }
        s_zgwd_loc->rssi_bar = NULL; s_zgwd_loc->rssi_lbl = NULL; s_zgwd_loc->pan_lbl = NULL;
        if (!s_zgwd_loc->task) { heap_caps_free(s_zgwd_loc); s_zgwd_loc = NULL; }
    }
    s_zgwd_da_lbl = NULL; s_zgwd_da_result = 0;
    if (s_zgwd_fld) {
        s_zgwd_fld->cancel = true;
        if (s_zgwd_fld->tmr) { lv_timer_del(s_zgwd_fld->tmr); s_zgwd_fld->tmr = NULL; }
        if (!s_zgwd_fld->task) { heap_caps_free(s_zgwd_fld); s_zgwd_fld = NULL; }
    }
    deauth_monitor_rec_label = NULL;
    bt_locator_content = NULL;
    bt_locator_list = NULL;
    bt_locator_status_label = NULL;
    bt_locator_rssi_label = NULL;
    bt_locator_mac_label = NULL;
    bt_locator_exit_btn = NULL;
    wifi_connect_ta = NULL;
    wifi_connect_keyboard = NULL;
    wifi_connect_status_label = NULL;
    wifi_connect_btn = NULL;
    wifi_connect_next_btn = NULL;
    if (sta_connect_check_timer) {
        lv_timer_del(sta_connect_check_timer);
        sta_connect_check_timer = NULL;
    }
    // WPA-SEC upload cleanup
    wpasec_status_list = NULL;
    wpasec_progress_label = NULL;
    wpasec_upload_active = false;  // Signal background task to stop
    if (wpasec_upload_timer) {
        lv_timer_del(wpasec_upload_timer);
        wpasec_upload_timer = NULL;
    }
    // Wardrive upload cleanup
    wdup_status_list      = NULL;
    wdup_wigle_key_ta     = NULL;
    wdup_wdg_key_ta       = NULL;
    wdup_progress_bar     = NULL;
    wdup_progress_lbl     = NULL;
    wdup_wigle_stat_lbl   = NULL;
    wdup_wdg_stat_lbl     = NULL;
    wdup_active           = false;
    if (wdup_timer) {
        lv_timer_del(wdup_timer);
        wdup_timer = NULL;
    }
}

