    lv_obj_set_style_text_color(dark_lbl, lv_color_hex(0x4A90D9), 0);
    lv_obj_center(dark_lbl);

    lv_obj_t *page_title_label = lv_label_create(page_title_bar);
    lv_label_set_text(page_title_label, name ? name : "");
