    lv_obj_t *spinner = lv_spinner_create(content, 1000, 60);
    lv_obj_set_size(spinner, 50, 50);
    lv_obj_align(spinner, LV_ALIGN_CENTER, 0, -20);

    lv_obj_t *scan_label = lv_label_create(content);
