    // Status line
    char s[56];
    snprintf(s, sizeof(s), "%d SSIDs - %d selected - tap to toggle",
             wana_ssid_count, sel_count);
    lv_obj_t *status = lv_label_create(wana_panel);
    lv_obj_set_size(status, 238, 18);
    lv_obj_set_pos(status, 1, 2);
