    // Button row (y=238 within panel)
    lv_obj_t *btns = lv_obj_create(wana_panel);
    lv_obj_set_size(btns, 240, 30);
    lv_obj_set_pos(btns, 0, 238);
    lv_obj_set_style_bg_opa(btns, LV_OPA_TRANSP, 0);
