    for (int i = 0; i < NRF24_NUM_PAGES; i++) {
        s_n24_pages[i] = s_n24_make_page(tc);
        if (i > 0) lv_obj_add_flag(s_n24_pages[i], LV_OBJ_FLAG_HIDDEN);
    }

    // Page 1: Core tools
